// Define quais ativos serão processados conforme o gatilho que disparou
const trigger = $input.first()?.json?.__triggerName || 'daily';
const assetsAll = [
  { key: 'IBOV', nome: 'Ibovespa (IBOV)',        yahoo: '^BVSP', yahooInterval: '1d',  yahooRange: '5d', timeframe: 'Gráfico Diário (1D)',                       tvSymbol: 'BMFBOVESPA:IBOV', tvInterval: 'D',  slug: 'ibovespa'    },
  { key: 'WIN',  nome: 'Mini Índice (WIN)',      yahoo: '^BVSP', yahooInterval: '15m', yahooRange: '1d', timeframe: 'Gráfico Intraday de 15 minutos (M15)',     tvSymbol: 'BMFBOVESPA:WIN1!', tvInterval: '15', slug: 'mini-indice'  },
  { key: 'WDO',  nome: 'Mini Dólar Futuro (WDO)', yahoo: 'BRL=X', yahooInterval: '15m', yahooRange: '1d', timeframe: 'Gráfico Intraday de 15 minutos (M15)',     tvSymbol: 'BMFBOVESPA:WDO1!', tvInterval: '15', slug: 'mini-dolar'   }
];
const isDaily = trigger.toLowerCase().includes('diário') || trigger.toLowerCase().includes('daily');
const filtered = isDaily ? assetsAll.filter(a => a.key === 'IBOV') : assetsAll.filter(a => a.key !== 'IBOV');
return filtered.map(a => ({ json: a }));

// Extrai OHLC do payload do Yahoo Finance
const input = $input.first().json;
const asset = $('Define Ativos').first().json;
const result = input?.chart?.result?.[0];
if (!result) throw new Error('Yahoo: resposta vazia para ' + asset.yahoo);
const meta = result.meta;
const q = result.indicators?.quote?.[0] || {};
const opens  = (q.open  || []).filter(v => v != null);
const highs  = (q.high  || []).filter(v => v != null);
const lows   = (q.low   || []).filter(v => v != null);
const closes = (q.close || []).filter(v => v != null);
const open  = opens[0];
const high  = Math.max(...highs);
const low   = Math.min(...lows);
const close = closes[closes.length - 1];
const prev  = meta.chartPreviousClose ?? meta.previousClose ?? open;
const pct   = ((close - prev) / prev) * 100;
const fmt = (v) => v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
return [{ json: { ...asset, open, high, low, close, percent_change: pct, openF: fmt(open), highF: fmt(high), lowF: fmt(low), closeF: fmt(close), pctF: pct.toFixed(2), changeClass: pct >= 0 ? 'positive' : 'negative', asOf: new Date().toISOString() }}];

