// Monta o HTML final usando o template e o texto gerado pelo Gemini
const gem = $input.first().json;
const d   = $('Parse OHLC').first().json;
const analiseTexto = (gem?.candidates?.[0]?.content?.parts?.[0]?.text || '').trim().replace(/^["']|["']$/g, '');
const publicadoEm = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

