</head><body><div class="c"><header class="h"><div class="brand">Genial Investimentos · Análise Técnica</div><div style="font-size:13px;color:#95a3bf">Abra sua conta em <a href="https://www.genialinvestimentos.com.br/abra-sua-conta/" style="color:#ffb800;text-decoration:none;font-weight:600">genialinvestimentos.com.br</a></div></header>
<h1 style="margin:0 0 6px">${d.nome} — Análise Técnica Diária</h1><div style="color:#95a3bf;font-size:14px;margin-bottom:24px">${d.timeframe} · ${publicadoEm}</div>
<div class="g"><section class="card"><div class="ch">Gráfico em tempo real · TradingView</div><div class="chart"><div class="tradingview-widget-container"><div id="tv_chart"></div><script src="https://s3.tradingview.com/tv.js"></script><script>new TradingView.widget({autosize:true,symbol:"${d.tvSymbol}",interval:"${d.tvInterval}",timezone:"America/Sao_Paulo",theme:"dark",style:"1",locale:"br",toolbar_bg:"#131c30",enable_publishing:false,hide_side_toolbar:false,allow_symbol_change:false,withdateranges:true,studies:["MASimple@tv-basicstudies","RSI@tv-basicstudies"],container_id:"tv_chart"});</script></div></div></section>
<aside class="card"><div class="ch">Análise do Pregão</div><div class="cb"><div class="row"><div class="cell"><span class="lbl">Fechamento</span><span class="val">${d.closeF}</span></div><div class="cell"><span class="lbl">Variação</span><span class="val ${d.changeClass}">${d.pctF}%</span></div><div class="cell"><span class="lbl">Máx.</span><span class="val">${d.highF}</span></div><div class="cell"><span class="lbl">Mín.</span><span class="val">${d.lowF}</span></div></div>
<p class="an">${analiseTexto}</p></div></aside></div>
<p class="disc"><strong>Aviso CVM/CNPI:</strong> Conteúdo informativo e educacional, baseado em análise técnica probabilística. Não constitui recomendação de compra, venda ou manutenção de ativos. Investimentos em renda variável envolvem riscos.</p>
</div></body></html>`;

return [{ json: { ...d, analiseTexto, html, publicadoEm }, binary: { data: { data: Buffer.from(html).toString('base64'), mimeType: 'text/html', fileName: `${d.slug}.html` } } }];
